#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int X[N], Y[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &X[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &Y[i]);
        }
        long long sum1 = 0, sum2 = 0;
        for (int i = 0; i < N; i++) {
            if (i % 2 == 0) {
                sum1 += X[i];
                sum2 += Y[i];
            } else {
                sum1 += Y[i];
                sum2 += X[i];
            }
        }
        printf("%lld\n", sum1 < sum2 ? sum1 : sum2);
    }
    return 0;
}

