code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] X = new int[N];
            int[] Y = new int[N];
            for (int i = 0; i < N; i++) {
                X[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                Y[i] = sc.nextInt();
            }
            long sum1 = 0, sum2 = 0;
            for (int i = 0; i < N; i++) {
                if (i % 2 == 0) {
                    sum1 += X[i];
                    sum2 += Y[i];
                } else {
                    sum1 += Y[i];
                    sum2 += X[i];
                }
            }
            System.out.println(Math.min(sum1, sum2));
        }
    }
}

